import React, { useState, useEffect } from 'react';

const TestScenarios: React.FC = () => {
  const [scenarios, setScenarios] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    const fetchScenarios = async () => {
      try {
        setLoading(true);
        console.log('Fetching scenarios from API...');
        const response = await fetch('http://localhost:5000/api/scenarios');
        const data = await response.json();
        console.log('Full API Response:', data);
        
        if (data.success) {
          console.log('Scenarios data:', data.data);
          console.log('Number of scenarios:', data.data.length);
          setScenarios(data.data);
        } else {
          setError('Failed to fetch scenarios: ' + data.message);
        }
      } catch (err) {
        console.error('Error fetching scenarios:', err);
        setError('Error fetching scenarios: ' + (err as Error).message);
      } finally {
        setLoading(false);
      }
    };

    fetchScenarios();
  }, []);

  if (loading) {
    return <div className="container mx-auto px-4 py-12">Loading...</div>;
  }

  if (error) {
    return <div className="container mx-auto px-4 py-12">Error: {error}</div>;
  }

  return (
    <div className="container mx-auto px-4 py-12">
      <h1 className="text-2xl font-bold mb-4">Test Scenarios</h1>
      <p className="mb-4">Number of scenarios: {scenarios.length}</p>
      
      {scenarios.map((scenario, index) => (
        <div key={scenario._id || index} className="bg-white p-4 rounded-lg shadow mb-4">
          <h2 className="text-xl font-bold">{scenario.title}</h2>
          <p><strong>Practice Area:</strong> {scenario.practiceArea}</p>
          <p><strong>Difficulty:</strong> {scenario.difficulty}</p>
          <p><strong>Estimated Time:</strong> {scenario.estimatedTime} minutes</p>
          <p><strong>Rating:</strong> {scenario.rating}</p>
          <p><strong>Review Count:</strong> {scenario.reviewCount}</p>
          <p><strong>Price:</strong> {scenario.price}</p>
          <p><strong>Status:</strong> {scenario.status}</p>
          <p><strong>Description:</strong> {scenario.description}</p>
        </div>
      ))}
    </div>
  );
};

export default TestScenarios;
